 *
 * This module is schema/data only — no DOM or React dependencies.
 */

/** Color tokens that every T3 Code theme must provide. */
export interface ThemeColorTokens {
  /** App-wide background */
  background: string;
  /** App-wide foreground / text color */
  foreground: string;
  /** Accent / primary action color */
  accent: string;
  /** Sidebar panel background */
  sidebar: string;
  /** Sidebar panel text color */
  sidebarForeground: string;
  /** Editor / main content area background */
  editor: string;
  /** Editor text color */
  editorForeground: string;
  /** Integrated terminal background */
  terminal: string;
  /** Integrated terminal text color */
  terminalForeground: string;
  /** Status bar background */
  statusBar: string;
  /** Status bar text color */
  statusBarForeground: string;
}

/** A complete theme definition. */
export interface ThemeDefinition {
  /** Unique theme identifier (e.g. "t3-dark") */
  id: string;
  /** Human-readable display name */
  name: string;
  /** Base appearance — controls `color-scheme` and the `.dark` CSS class */
  appearance: "light" | "dark";
  /** Color palette for every surface area */
  colors: ThemeColorTokens;
}

/** Union of built-in theme IDs. */
export type BuiltInThemeId = "t3-light" | "t3-dark" | "t3-midnight";

