/**
 * Theme type definitions and built-in themes for T3 Code.
 *
 * This module is schema/data only — no DOM or React dependencies.
 */

/** Color tokens that every T3 Code theme must provide. */
export interface ThemeColorTokens {
  /** App-wide background */
  background: string;
  /** App-wide foreground / text color */
  foreground: string;
  /** Accent / primary action color */
  accent: string;
  /** Sidebar panel background */
  sidebar: string;
  /** Sidebar panel text color */
  sidebarForeground: string;
  /** Editor / main content area background */
  editor: string;
  /** Editor text color */
  editorForeground: string;
  /** Integrated terminal background */
  terminal: string;
  /** Integrated terminal text color */
  terminalForeground: string;
  /** Status bar background */
  statusBar: string;
  /** Status bar text color */
  statusBarForeground: string;
}

/** A complete theme definition. */
export interface ThemeDefinition {
  /** Unique theme identifier (e.g. "t3-dark") */
  id: string;
  /** Human-readable display name */
  name: string;
  /** Base appearance — controls `color-scheme` and the `.dark` CSS class */
  appearance: "light" | "dark";
  /** Color palette for every surface area */
  colors: ThemeColorTokens;
}

/** Union of built-in theme IDs. */
export type BuiltInThemeId = "t3-light" | "t3-dark" | "t3-midnight";

/** Ordered list of built-in themes. */
export const BUILT_IN_THEMES: readonly ThemeDefinition[] = [
  {
    id: "t3-light",
    name: "T3 Light",
    appearance: "light",
    colors: {
      background: "#ffffff",
      foreground: "#1c1c1e",
      accent: "#6d28d9",
      sidebar: "#f5f5f7",
      sidebarForeground: "#3a3a3c",
      editor: "#ffffff",
      editorForeground: "#1c1c1e",
      terminal: "#f0f0f2",
      terminalForeground: "#1c1c1e",
      statusBar: "#6d28d9",
      statusBarForeground: "#ffffff",
    },
  },
  {
    id: "t3-dark",
    name: "T3 Dark",
    appearance: "dark",
    colors: {
      background: "#0f0f11",
      foreground: "#e4e4e7",
      accent: "#8b5cf6",
      sidebar: "#18181b",
      sidebarForeground: "#a1a1aa",
      editor: "#0f0f11",
      editorForeground: "#e4e4e7",
      terminal: "#09090b",
      terminalForeground: "#a1a1aa",
      statusBar: "#7c3aed",
      statusBarForeground: "#ffffff",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    appearance: "dark",
    colors: {
      background: "#020617",
      foreground: "#cbd5e1",
      accent: "#6366f1",
      sidebar: "#0f172a",
      sidebarForeground: "#94a3b8",
      editor: "#020617",
      editorForeground: "#cbd5e1",
      terminal: "#000000",
      terminalForeground: "#64748b",
      statusBar: "#4f46e5",
      statusBarForeground: "#e0e7ff",
    },
  },
];

/** Map of theme IDs to definitions for O(1) lookup. */
export const BUILT_IN_THEME_MAP: ReadonlyMap<string, ThemeDefinition> = new Map(
  BUILT_IN_THEMES.map((t) => [t.id, t]),
);

/** Default theme ID used when nothing is persisted. */
export const DEFAULT_THEME_ID: BuiltInThemeId = "t3-dark";

/** Resolve a theme definition by ID, falling back to the default theme. */
export function resolveThemeById(id: string): ThemeDefinition {
  return BUILT_IN_THEME_MAP.get(id) ?? BUILT_IN_THEME_MAP.get(DEFAULT_THEME_ID)!;
}

