import {
  createContext,
  useCallback,
  useEffect,
  useMemo,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  resolveThemeById,
  type ThemeDefinition,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Module-level external store (singleton — shared across all ThemeProvider
// instances so theme is consistent app-wide and survives remounts).
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";

let listeners: Array<() => void> = [];
let cachedSnapshot: { themeId: string } | null = null;

function emit() {
  for (const fn of listeners) fn();
}

function getStoredId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && BUILT_IN_THEMES.some((t) => t.id === raw)) return raw;
  return DEFAULT_THEME_ID;
}

// ---------------------------------------------------------------------------
// DOM side-effects
// ---------------------------------------------------------------------------

/** Write every ThemeColorTokens field as a CSS custom property on :root. */
function applyCssProperties(theme: ThemeDefinition) {
  const s = document.documentElement.style;
  s.setProperty("--theme-background", theme.colors.background);
  s.setProperty("--theme-foreground", theme.colors.foreground);
  s.setProperty("--theme-accent", theme.colors.accent);
  s.setProperty("--theme-sidebar", theme.colors.sidebar);
  s.setProperty("--theme-sidebar-foreground", theme.colors.sidebarForeground);
  s.setProperty("--theme-editor", theme.colors.editor);
  s.setProperty("--theme-editor-foreground", theme.colors.editorForeground);
  s.setProperty("--theme-terminal", theme.colors.terminal);
  s.setProperty("--theme-terminal-foreground", theme.colors.terminalForeground);
  s.setProperty("--theme-status-bar", theme.colors.statusBar);
  s.setProperty("--theme-status-bar-foreground", theme.colors.statusBarForeground);
}

function applyTheme(themeId: string, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const theme = resolveThemeById(themeId);
  document.documentElement.classList.toggle("dark", theme.appearance === "dark");
  applyCssProperties(theme);

  if (suppressTransitions) {
    // Force reflow so `no-transitions` takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of wrong theme.
applyTheme(getStoredId());

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): { themeId: string } {
  const id = getStoredId();
  if (cachedSnapshot && cachedSnapshot.themeId === id) return cachedSnapshot;
  cachedSnapshot = { themeId: id };
  return cachedSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Keep in sync when another tab changes the stored theme.
  const onStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredId(), true);
      emit();
    }
  };
  window.addEventListener("storage", onStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", onStorage);
  };
}

// ---------------------------------------------------------------------------
// React context
// ---------------------------------------------------------------------------

export interface ThemeContextValue {
  /** Current theme ID (e.g. "t3-dark"). */
  theme: string;
  /** Switch to a different theme by ID. */
  setTheme: (id: string) => void;
  /** Resolved base appearance: always "light" or "dark". */
  resolvedTheme: "light" | "dark";
  /** Full definition for the currently active theme. */
  themeDefinition: ThemeDefinition;
  /** All available built-in themes. */
  themes: readonly ThemeDefinition[];
}

export const ThemeContext = createContext<ThemeContextValue | null>(null);

/**
 * Provides theme state to the React tree. Persists the selected theme to
 * `localStorage` and applies CSS custom properties + the `.dark` class on
 * `<html>` whenever the theme changes.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const definition = resolveThemeById(snapshot.themeId);

  const setTheme = useCallback((id: string) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(id, true);
    emit();
  }, []);

  // Re-apply on mount / when themeId changes (covers HMR & hydration).
  useEffect(() => {
    applyTheme(snapshot.themeId);
  }, [snapshot.themeId]);

  const value: ThemeContextValue = useMemo(
    () => ({
      theme: snapshot.themeId,
      setTheme,
      resolvedTheme: definition.appearance,
      themeDefinition: definition,
      themes: BUILT_IN_THEMES,
    }),
    [snapshot.themeId, setTheme, definition],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

