import type { ThemeDefinition } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch preview — mini representation of a theme's key surfaces.
// ---------------------------------------------------------------------------

function ThemePreviewSwatch({ theme }: { theme: ThemeDefinition }) {
  const c = theme.colors;

  return (
    <div
      className="flex h-14 w-full overflow-hidden rounded-md border border-border"
      style={{ background: c.background }}
    >
      {/* Sidebar strip */}
      <div className="flex w-6 shrink-0 flex-col" style={{ background: c.sidebar }}>
        <div className="mx-auto mt-1.5 h-1 w-3 rounded-full opacity-40" style={{ background: c.sidebarForeground }} />
        <div className="mx-auto mt-1 h-1 w-3 rounded-full opacity-25" style={{ background: c.sidebarForeground }} />
        <div className="mx-auto mt-1 h-1 w-3 rounded-full opacity-25" style={{ background: c.sidebarForeground }} />
      </div>

      {/* Main area */}
      <div className="flex min-w-0 flex-1 flex-col">
        {/* Editor region */}
        <div className="flex-1 px-1.5 pt-1.5" style={{ background: c.editor }}>
          <div className="h-1 w-10 rounded-full opacity-30" style={{ background: c.editorForeground }} />
          <div className="mt-1 h-1 w-14 rounded-full opacity-20" style={{ background: c.editorForeground }} />
          <div className="mt-1 h-1 w-8 rounded-full opacity-20" style={{ background: c.editorForeground }} />
        </div>

        {/* Terminal strip */}
        <div className="h-3 px-1.5 pt-0.5" style={{ background: c.terminal }}>
          <div className="h-1 w-8 rounded-full opacity-25" style={{ background: c.terminalForeground }} />
        </div>

        {/* Status bar */}
        <div className="flex h-2.5 items-center px-1.5" style={{ background: c.statusBar }}>
          <div className="h-0.5 w-4 rounded-full opacity-60" style={{ background: c.statusBarForeground }} />
          <div className="ml-auto h-0.5 w-3 rounded-full opacity-40" style={{ background: c.statusBarForeground }} />
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Individual theme option row.
// ---------------------------------------------------------------------------

function ThemeOption({
  theme,
  selected,
  onSelect,
}: {
  theme: ThemeDefinition;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={theme.name}
      className={`flex w-full items-center gap-4 rounded-lg border px-3 py-2.5 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={onSelect}
    >
      {/* Preview swatch */}
      <div className="w-28 shrink-0">
        <ThemePreviewSwatch theme={theme} />
      </div>

      {/* Label & metadata */}
      <div className="flex min-w-0 flex-1 flex-col gap-0.5">
        <span className="text-sm font-medium">{theme.name}</span>
        <span className="text-xs capitalize opacity-70">{theme.appearance} appearance</span>
      </div>

      {/* Selection badge */}
      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

// ---------------------------------------------------------------------------
// Public ThemeSelector component.
// ---------------------------------------------------------------------------

/**
 * Renders a radio-group of built-in themes, each showing a color-swatch
 * preview. Persists the user's choice via the ThemeProvider.
 */
export function ThemeSelector() {
  const { theme, setTheme, resolvedTheme, themes } = useTheme();

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
        {themes.map((t) => (
          <ThemeOption
            key={t.id}
            theme={t}
            selected={theme === t.id}
            onSelect={() => setTheme(t.id)}
          />
        ))}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active appearance:{" "}
        <span className="font-medium capitalize text-foreground">{resolvedTheme}</span>
      </p>
    </div>
  );
}
